"use strict";parserFactory.register("wattpad.com.vn",()=>new WattpadVNParser);class WattpadVNParser extends Parser{constructor(){super()}async getChapterUrls(t,e){this.extractNovelId(t);let r=[],l=1,a=1;for(;l<=a;){let n=`https://wattpad.com.vn/get/listchap/${this.novelId}?page=${l}`,o={headers:{"X-Requested-With":"XMLHttpRequest"}},c=(await HttpClient.fetchJson(n,o)).json.data,i=(new DOMParser).parseFromString(c,"text/html"),u=[],s=i.querySelectorAll("ul");for(let e of s){let r=e.querySelectorAll("a");for(let e of r){let r=e.getAttribute("href"),l=new URL(r,t.baseURI).href;u.push({sourceUrl:l,title:e.textContent.trim()})}}e.showTocProgress(u),r=r.concat(u),1===l&&(a=this.extractMaxPages(i)),l++,await this.rateLimitDelay()}return r}extractNovelId(t){let e=t.querySelector(".findchap > input:nth-child(2)");this.novelId=e?.value}extractMaxPages(t){let e=t.querySelector(".paging");if(!e)return 1;let r=e.querySelectorAll("a"),l=1;for(let t of r){let e=t.getAttribute("onclick");if(e){let t=e.match(/page\(\d+,(\d+)\)/);t&&(l=Math.max(l,parseInt(t[1])))}}return l}findContent(t){return t.querySelector(".truyen")}extractTitleImpl(t){return t.querySelector(".mRightCol > h1:nth-child(1)")}extractAuthor(t){let e=t.querySelector(".book-info-text > ul:nth-child(1) > li:nth-child(1) > a:nth-child(2)");return e?.textContent??super.extractAuthor(t)}extractLanguage(t){return t.querySelector("html").getAttribute("lang")}extractSubject(t){return[...t.querySelectorAll(".li--genres > a:nth-child(2)")].map(t=>t.textContent.trim()).join(", ")}extractDescription(t){return t.querySelector(".intro").textContent.trim()}findChapterTitle(t){return t.querySelector(".current-chapter > a:nth-child(1)")}findCoverImageUrl(t){return util.getFirstImgSrc(t,".book-3d")}}